function Testmonial({ carouselId = "testimonialCarousel" }) {
    return (
        <>
            <div className="container py-5">
                <div id={carouselId} className="carousel slide my-5" data-bs-ride="carousel">
                    <div className="carousel-inner text-center">
                        <div className="carousel-item active">
                            <div className="testimonial">
                                <p className="w-75 mx-auto">
                                    <span className='fa-solid fa-quote-left cls-icn-sz cls-color-org'></span> &nbsp; Great service and amazing experience. The team was very
                                    professional and delivered beyond expectations. &nbsp;<span className='fa-solid fa-quote-right cls-icn-sz cls-color-org'></span>
                                </p>
                                <small className='cls-color-org'>John Doe</small>
                            </div>
                        </div>
                        <div className="carousel-item">
                            <div className="testimonial">
                                <p className="w-75 mx-auto">
                                    <span className='fa-solid fa-quote-left cls-icn-sz cls-color-org'></span> &nbsp; Outstanding support and quick delivery. I highly recommend their services. &nbsp;<span className='fa-solid fa-quote-right cls-icn-sz cls-color-org'></span>
                                </p>
                                <small className='cls-color-org'>Sarah Smith</small>
                            </div>
                        </div>
                        <div className="carousel-item">
                            <div className="testimonial">
                                <p className="w-75 mx-auto">
                                    <span className='fa-solid fa-quote-left cls-icn-sz cls-color-org'></span> &nbsp;
                                    Professional team and beautiful design work. Very satisfied
                                    with the final result. &nbsp;<span className='fa-solid fa-quote-right cls-icn-sz cls-color-org'></span>
                                </p>
                                <small className='cls-color-org'>Michael Brown</small>
                            </div>
                        </div>
                    </div>

                    <button
                        className="carousel-control-prev"
                        type="button"
                        data-bs-target={`#${carouselId}`}
                        data-bs-slide="prev">
                        <span className="carousel-control-prev-icon"></span>
                    </button>

                    <button
                        className="carousel-control-next"
                        type="button"
                        data-bs-target={`#${carouselId}`}
                        data-bs-slide="next">
                        <span className="carousel-control-next-icon"></span>
                    </button>
                </div>
            </div>
        </>
    )
}

export default Testmonial;