import { TeamCardTemp } from '../../components/Card';
import { FrstImageInfo, FrstInfoImage } from '../../components/ImageInfo';
import Testmonial from '../../components/Testimonial';
import { useNavigate } from 'react-router-dom';

function MainHome() {
    const navigate = useNavigate();

    const handleRouting = (route, pageName) => {
        navigate(route, { state: pageName ? { pageName: pageName, imageSrc: "beautiful-beach-using-young-happy.jpg" } : null });
    };


    const teamCardSet = [
        {
            "id": 1, "imagesrc": "grayscale-photo-smiling-woman-wearing-turtleneck-top.jpg", "name": "Alice Johnson", "designation": "Software Engineer"
        },
        { "id": 2, "imagesrc": "front-view-authentic-woman-posing.jpg", "name": "Bob Smith", "designation": "Product Manager" },
        { "id": 3, "imagesrc": "front-view-smiley-woman-posing-black-white.jpg", "name": "Charlie Brown", "designation": "UX Designer" },
        { "id": 4, "imagesrc": "front-view-woman-posing-black-white.jpg", "name": "Diana Lee", "designation": "Quality Analyst" },
    ]

    return (
        <>
            <section className='fade-in-section'>
                <div className="container-fluid p-0">
                    <div id="testimonialCarousel" className="carousel slide" data-bs-ride="carousel">
                        <div className="carousel-inner text-center">
                            <div className="carousel-item active">
                                <div className="testimonial">
                                    <div className='cls-home1-cont-imgs1 d-flex justify-content-center align-items-center' >
                                        <div className='cls-content-holder'>
                                            <h1 className='mb-3 p-2 cls-shdow-text'>Discover New Faces</h1>
                                            <p className='cls-shdow-text'>We connect talented models with brands, designers, and creative projects across the fashion industry.</p>
                                            <button className='btn commn-btn cls-shdow-text'>Explore More</button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="carousel-item">
                                <div className="testimonial">
                                    <div className='cls-home1-cont-imgs2 d-flex justify-content-center align-items-center' >
                                        <div className='cls-content-holder'>
                                            <h1 className='mb-3 p-2 cls-shdow-text'>Fashion Meets Talent</h1>
                                            <p className='cls-shdow-text'>Our agency supports models in building strong portfolios and finding the right opportunities.</p>
                                            <button className='btn commn-btn cls-shdow-text'>View Our Work</button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="carousel-item">
                                <div className="testimonial">
                                    <div className='cls-home1-cont-imgs3 d-flex justify-content-center align-items-center' >
                                        <div className='cls-content-holder'>
                                            <h1 className='mb-3 p-2 cls-shdow-text'>Create Bold Campaigns</h1>
                                            <p className='cls-shdow-text'>Working with brands and creative teams to produce impactful fashion and promotional campaigns.</p>
                                            <button className='btn commn-btn cls-shdow-text'>Contact Us</button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <button
                            className="carousel-control-prev"
                            type="button"
                            data-bs-target="#testimonialCarousel"
                            data-bs-slide="prev">
                            <span className="carousel-control-prev-icon"></span>
                        </button>

                        <button
                            className="carousel-control-next"
                            type="button"
                            data-bs-target="#testimonialCarousel"
                            data-bs-slide="next">
                            <span className="carousel-control-next-icon"></span>
                        </button>
                    </div>
                </div>
            </section>
            <section className=''>
                <div className='container pt-5'>
                    <div className='row'>
                        <div className='col-md-6 my-5 text-end pe-5'>
                            <h2>Fashion Talent</h2>
                        </div>
                        <div className='col-md-6 my-5'>
                            <p>Our agency is dedicated to supporting and developing modeling talent while building meaningful connections within the fashion and creative industry. We collaborate with brands, photographers, designers, and creative teams to create opportunities that highlight individuality, confidence, and professionalism. From fashion campaigns and editorial shoots to promotional events and creative productions, our focus is on bringing ideas to life through strong visual storytelling. By combining creativity with industry experience, we aim to create an environment where talent can grow, express themselves, and build lasting careers in the world of fashion.</p>
                        </div>
                    </div>
                </div>
            </section>
            <section>
                <FrstImageInfo handleRouting={handleRouting} />
                <FrstInfoImage handleRouting={handleRouting} />
            </section>
            <section>
                <div className='container pt-5 pb-5'>
                    <div className='row'>
                        <div className='col-md-12 text-center'>
                            <h2 className='mb-4'>Our Team</h2>
                            <h5>About Our Team</h5>
                            <p>Our team brings together experience, creativity, and dedication to support every project we take on. By working closely with models, brands, and creative professionals, we ensure that every collaboration is handled with care, professionalism, and a strong focus on quality.</p>
                        </div>
                        <TeamCardTemp teamArr={teamCardSet} />
                    </div>
                </div>
            </section>
            <section>
                <FrstImageInfo handleRouting={handleRouting} />
            </section>
            <section>
                <Testmonial carouselId="testimonialCarouselHome1" />
            </section>

        </>
    )
}

export default MainHome;