
export function Cards1(props) {
    return (
        <>
            <div className='cls-card-set1 my-4' data-aos="fade-up" data-aos-duration="600">
                <h5>{props.id}</h5>
                <h6>{props.title}</h6>
                <p>{props.descrp}</p>
            </div>
        </>
    )
}


export function Cards2(props) {
    return (
        <>
            <div className='cls-card-set2' data-aos="fade-up" data-aos-duration="600">
                <div className='cls-team-img'>
                    <img
                        src={process.env.PUBLIC_URL + `/images/` + props.imagesrc}
                        className="img-fluid"
                        alt="props.imagesrc"
                    />
                </div>
                <div className='row d-flex justify-content-between'>
                    <div className="cls-user-content ">
                        <h6 >{props.name}</h6>
                        <p >{props.design}</p>
                    </div>

                    <div className="cls-team-sclmedia d-flex align-items-center">
                        <span className='cls-icn-sz fa-brands fa-facebook-f p-2'></span>
                        <span className='cls-icn-sz fa-brands fa-instagram p-2'></span>
                        <span className='cls-icn-sz fa-brands fa-linkedin p-2 pe-3'></span>
                    </div>
                </div>
            </div>
        </>
    )
}

export function InfoCards(params) {
    const infoCardSet = params?.infoArr || [];
    return (
        <>
            {
                infoCardSet.map((cardData) =>
                    <div className='col-md-4' key={cardData.id}>
                        <Cards1 title={cardData.title.toUpperCase()} descrp={cardData.description} id={cardData.id} />
                    </div>
                )
            }

        </>
    )
}

export function TeamCardTemp(params) {

    const teamCardSet = params?.teamArr || [];
    return (
        <>
            {
                teamCardSet.map((teamData) =>
                    <div className='col-md-3 p-2' key={teamData.id}>
                        <Cards2 name={teamData.name} imagesrc={teamData.imagesrc} design={teamData.designation} id={teamData.id} />
                    </div>
                )
            }
        </>
    )
}


